window.YPP=window.YPP||{};window.YPP.features=window.YPP.features||{};window.YPP.features.DataAPI=class extends window.YPP.features.BaseFeature{constructor(){super("DataAPI"),this.apiKey=null,this.clientName=null,this.clientVersion=null,this.context=null,this.loggedOnly=!1}disable(){}init(){this.extractData()}extractData(){try{this.scrapeFromScriptTags(),this.apiKey}catch(t){console.error("[YPP DataAPI] Extraction error:",t)}}scrapeFromScriptTags(){const t=document.querySelectorAll("script");for(const e of t)if(e.textContent&&e.textContent.includes("INNERTUBE_API_KEY")){const i=e.textContent,s=i.match(/"INNERTUBE_API_KEY":\s*"([^"]+)"/),n=i.match(/"INNERTUBE_CLIENT_VERSION":\s*"([^"]+)"/),a=i.match(/"INNERTUBE_CLIENT_NAME":\s*"([^"]+)"/);if(s&&(this.apiKey=s[1]),n&&(this.clientVersion=n[1]),a&&(this.clientName=a[1]),this.apiKey)break}}getHeaders(){var t,e;return this.apiKey?{"X-Goog-Visitor-Id":((e=(t=this.context)==null?void 0:t.client)==null?void 0:e.visitorData)||"","X-Youtube-Client-Name":this.clientName||"1","X-Youtube-Client-Version":this.clientVersion||"2.20210101.00.00"}:null}};
